SELECT
  rq.id,
  p.id,
  rq.symbol,
  'KRX',
  '1w',
  rq.difficulty,
  'bull'::market_regime,
  rq.base_date,
  rq.chart_data,
  rq.actual_next_candles,
  rq.correct_answer,
  rq.ai_explanation,
  rq.rule_score,
